def _sha256_bytes(data):
    return hashlib.sha256(data).hexdigest()


def _sha256_text(text):
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def _decode_embedded_source_bytes():
    try:
        raw = lzma.decompress(base64.b85decode(_EMBEDDED_SOURCE_B85))
    except Exception as exc:
        raise RuntimeError("Unable to decode embedded PE ablation source payload") from exc

    raw_bytes = len(raw)
    if raw_bytes != EMBEDDED_SOURCE_BYTES:
        raise RuntimeError(
            "Embedded PE ablation source byte count mismatch: got {}, expected {}".format(
                raw_bytes, EMBEDDED_SOURCE_BYTES
            )
        )

    raw_hash = _sha256_bytes(raw)
    if raw_hash != EMBEDDED_SOURCE_SHA256:
        raise RuntimeError(
            "Embedded PE ablation source SHA256 mismatch: got {}, expected {}".format(
                raw_hash, EMBEDDED_SOURCE_SHA256
            )
        )
    return raw


def _replace_once(text, old, new):
    if old not in text:
        raise RuntimeError("Expected template normalization fragment not found: {!r}".format(old[:80]))
    return text.replace(old, new, 1)


def get_template_source(repo_root=None):
    """Return the reviewed #1809-style template source as valid Python text."""
    del repo_root  # Signature retained for caller compatibility; source is embedded.
    source = _decode_embedded_source_bytes().decode("utf-8")
    source = _replace_once(
        source,
        'for cat in sorted(categories):log(f"  {cat}: {", ".join(sorted(categories[cat]))}")',
        'for cat in sorted(categories):log(f"  {cat}: {\', \'.join(sorted(categories[cat]))}")',
    )
    source = _replace_once(
        source,
        'log(f"train_shards: {len(list(Path(h.datasets_dir).resolve().glob("fineweb_train_*.bin")))}");',
        'log(f"train_shards: {len(list(Path(h.datasets_dir).resolve().glob(\'fineweb_train_*.bin\')))}");',
    )
    return source


def get_template_metadata(repo_root=None):
    """Return self-contained provenance metadata for dry-run audit output."""
    del repo_root  # Signature retained for caller compatibility; source is embedded.
    template_text = Path(__file__).read_text(encoding="utf-8")
    embedded_source = _decode_embedded_source_bytes()
    return {
        "payload_description": PAYLOAD_DESCRIPTION,
        "exact_upstream_1809": EXACT_UPSTREAM_1809,
        "template_path": str(Path(__file__).resolve()),
        "template_sha256": _sha256_text(template_text),
        "embedded_source_sha256": _sha256_bytes(embedded_source),
        "embedded_source_bytes": len(embedded_source),
    }